#!/usr/bin/env node

/**
 * Bundle .agents/ content into src/content.js
 *
 * Reads every file from ../../.agents/ and generates a JS module
 * exporting a FILES object mapping relative paths to file content strings.
 *
 * Run: node scripts/bundle-content.js
 */

import fs from 'node:fs';
import path from 'node:path';
import { fileURLToPath } from 'node:url';

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const agentsDir = path.resolve(__dirname, '..', '..', '..', '.agents');
const outputFile = path.resolve(__dirname, '..', 'src', 'content.js');

function walk(dir, base) {
  const entries = [];
  for (const entry of fs.readdirSync(dir, { withFileTypes: true })) {
    const fullPath = path.join(dir, entry.name);
    const relPath = path.join(base, entry.name);
    if (entry.isDirectory()) {
      entries.push(...walk(fullPath, relPath));
    } else if (entry.isFile()) {
      entries.push({ relPath, fullPath });
    }
  }
  return entries;
}

if (!fs.existsSync(agentsDir)) {
  console.error(`Error: .agents/ directory not found at ${agentsDir}`);
  process.exit(1);
}

const files = walk(agentsDir, '');
const manifest = {};

for (const { relPath, fullPath } of files) {
  const content = fs.readFileSync(fullPath, 'utf-8');
  const key = relPath.split(path.sep).join('/');
  manifest[key] = content;
}

const output = `// Auto-generated by scripts/bundle-content.js
// Source: .agents/ directory
// Do not edit manually — run: npm run bundle

export const FILES = ${JSON.stringify(manifest, null, 2)};
`;

fs.writeFileSync(outputFile, output, 'utf-8');
console.log(`Bundled ${Object.keys(manifest).length} files into src/content.js`);
